                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="_model.StudentName" />
                    <ValidationMessage For="() => _model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId" />
                    <ValidationMessage For="() => _model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in _courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.CourseId" />
                </div>

                <div class="mb-3">
                    <label for="comments" class="form-label">Comments (optional)</label>
                    <InputTextArea id="comments" class="form-control" rows="3" @bind-Value="_model.Comments" />
                    <ValidationMessage For="() => _model.Comments" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    [SupplyParameterFromForm] private EnrollmentRequest _model { get; set; } = new();

    private List<Course> _courses = new();
    private bool _submitted;
    private string _selectedCourseDisplay = string.Empty;

    protected override void OnInitialized()
    {
        _courses = Catalog.GetAllCourses();

        if (CourseId.HasValue && _model.CourseId == 0)
        {
            _model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(_model.CourseId);
        _selectedCourseDisplay = course is not null ? $"{course.Code} — {course.Title}" : "Unknown Course";
        _submitted = true;
    }
}

