@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse departments, explore courses, and submit your enrollment request for Fall 2026.</p>

<hr />

<h2>Featured Courses</h2>
<div class="row">
    @foreach (var course in _featuredCourses)
    {
        var dept = Catalog.GetDepartment(course.DepartmentId);
        <div class="col-md-6 col-lg-4 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                    <span class="badge bg-primary me-1">@course.Credits credits</span>
                    <span class="badge bg-secondary">@dept?.Name</span>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<hr />

<h2>Departments</h2>
<div class="row">
    @foreach (var dept in _departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text text-muted">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-sm btn-outline-secondary">
                        Browse @dept.Code Courses
                    </a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> _featuredCourses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _featuredCourses = Catalog.GetFeaturedCourses();
        _departments = Catalog.GetAllDepartments();
    }

    private static string Truncate(string text, int maxLength)
    {
        if (text.Length <= maxLength) return text;
        return text[..maxLength].TrimEnd() + "…";
    }
}

